        whenNeitherOperandZero
    {
        SD59x18 actual = avg(s.x, s.y);
        assertEq(actual, s.expected, "SD59x18 avg");
    }

    function bothOperandsNegative_Sets() internal returns (Set[] memory) {
        delete sets;
        sets.push(
